cq:
objective:'Connect swing lows so the line supports the up-move and respects 2–3 touches.',prompt:'Draw the support line under the rising lows',
gen:(s,d)=>{const n=DIFF_N[d],vol=DIFF_VOL[d],r=rng(s),base=58,slope=vol*0.5+1.0,cs=[];
  for(let i=0;i<n;i++){const lineLo=base+i*slope,o=i?cs[i-1].c:lineLo+vol;let c;
    if(i>0&&r()<0.34){c=o-(0.5+r()*1.3)*vol;}                                   // RED pullback candle (realism)
    else{c=Math.max(o+(0.3+r()*1.1)*vol,lineLo+(1.0+r()*1.8)*vol*0.4);}          // GREEN up candle
    const lo=Math.min(o,c,lineLo+r()*0.3*vol)-vol*0.2;
    cs.push({o,c,hi:Math.max(o,c)+vol*0.4,lo});}
  const pv=pivots(cs,2),lows=pv.L.length>=2?pv.L:[Math.floor(n*0.2),Math.floor(n*0.6)];return{cs,lows,extra:[]};},
